-- Hash store: one row per source document
CREATE TABLE IF NOT EXISTS doc_hashes (
    doc_id      TEXT PRIMARY KEY,
    content_md5 CHAR(32) NOT NULL,
    synced_at   TIMESTAMPTZ NOT NULL DEFAULT now()
);

-- Vector store: one row per chunk
CREATE TABLE IF NOT EXISTS doc_chunks (
    id            TEXT PRIMARY KEY,   -- '{doc_id}::{ordinal}'
    source_doc_id TEXT NOT NULL,
    chunk_text    TEXT NOT NULL,
    embedding     vector(1024)
);
CREATE INDEX IF NOT EXISTS idx_chunks_source ON doc_chunks (source_doc_id);

import pathlib, psycopg2

conn = psycopg2.connect("postgresql://localhost/ragdb")
psycopg2.extras.register_vector(conn)

docs_dir = pathlib.Path("./knowledge-base")
source_docs = [
    {"id": str(p), "text": p.read_text()}
    for p in docs_dir.rglob("*.txt")
]

stats = sync_docs(conn, source_docs)
print(f"Sync complete: {stats}")
